# E2e tests for category: edge-cases
# Generated by html-to-markdown-e2e-generator — do not edit manually.

library(testthat)
library(htmltomarkdown)

test_that("empty_html: Empty HTML document", {
  html <- "<html><head></head><body></body></html>"
  result <- convert(html)
  content <- result$content %||% ""

  expect_equal(trimws(content), "")
})

test_that("encoding_cjk_characters: CJK (Chinese, Japanese, Korean) characters are preserved", {
  html <- "<p>中文内容</p><p>日本語テキスト</p><p>한국어 텍스트</p>"
  result <- convert(html)
  content <- result$content %||% ""

  expect_true(nchar(trimws(content)) > 0)
  # content_contains_all
  expect_true(grepl("中文内容", content, fixed = TRUE))
  expect_true(grepl("日本語テキスト", content, fixed = TRUE))
  expect_true(grepl("한국어 텍스트", content, fixed = TRUE))
})

test_that("encoding_html_entities: Common HTML entities are decoded in output", {
  html <- "<p>&amp; &lt; &gt; &nbsp; &quot; &apos;</p>"
  result <- convert(html)
  content <- result$content %||% ""

  expect_true(nchar(trimws(content)) > 0)
  # content_contains_all
  expect_true(grepl("&", content, fixed = TRUE))
  expect_true(grepl("<", content, fixed = TRUE))
  expect_true(grepl(">", content, fixed = TRUE))
})

test_that("encoding_named_entities: Named HTML entities like &mdash; and &hellip; are decoded", {
