test_that("xss_javascript_url_blocked: javascript: URLs in href attributes are blocked and not included in output", {
  html <- "<p><a href=\"javascript:alert('xss')\">Click me</a></p>"
  result <- convert(html)
  content <- result$content %||% ""

  expect_true(nchar(trimws(content)) > 0)
  # content_contains_all
  expect_true(grepl("Click me", content, fixed = TRUE))
  # content_not_contains
  expect_false(grepl("javascript:", content, fixed = TRUE))
  expect_false(grepl("alert(", content, fixed = TRUE))
})

test_that("xss_onclick_handler_removed: onclick and other on* event handlers are removed from elements", {
  html <- "<p><a href=\"https://example.com\" onclick=\"alert('xss')\">Click me</a></p><button onmouseover=\"steal_data()\">Hover me</button>"
  result <- convert(html)
  content <- result$content %||% ""

  expect_true(nchar(trimws(content)) > 0)
  # content_contains_all
  expect_true(grepl("Click me", content, fixed = TRUE))
  # content_not_contains
  expect_false(grepl("onclick", content, fixed = TRUE))
  expect_false(grepl("onmouseover", content, fixed = TRUE))
  expect_false(grepl("alert(", content, fixed = TRUE))
  expect_false(grepl("steal_data", content, fixed = TRUE))
})

test_that("xss_script_tag_stripped: Script tag content is stripped and does not appear in output", {
  html <- "<p>Safe content.</p><script>alert('xss')</script><p>More safe content.</p>"
  result <- convert(html)
  content <- result$content %||% ""

  expect_true(nchar(trimws(content)) > 0)
  # content_contains_all
  expect_true(grepl("Safe content", content, fixed = TRUE))
  expect_true(grepl("More safe content", content, fixed = TRUE))
  # content_not_contains
  expect_false(grepl("<script>", content, fixed = TRUE))
  expect_false(grepl("alert(", content, fixed = TRUE))
  expect_false(grepl("xss", content, fixed = TRUE))
})

test_that("xss_svg_nested_script_stripped: Script tags nested inside SVG are stripped", {
  html <- "<p>Before SVG.</p><svg xmlns=\"http://www.w3.org/2000/svg\"><script>alert('svg-xss')</script><text>SVG text</text></svg><p>After SVG.</p>"
